CODE_EXAMPLE:
// Before
int fivePercentRaise() {
  return salary * 1.05;
}

int tenPercentRaise() {
  return salary * 1.10;
}

// After
int raise(double factor) {
  return salary * factor;
}

// Calls
raise(1.05);
raise(1.10);

UNIT_TEST_EXAMPLE:
@Test
public void testParameterize() {
  Employee employee = new Employee(1000);
  int raised = employee.raise(1.05);
  assertEquals(1050, raised);
}
